class Solution:
    def sortPeople(self, names, heights):
        pairs = list(zip(heights, names))
        result = []
        used = [False] * len(pairs)
        for _ in range(len(pairs)):
            best = -1
            for i in range(len(pairs)):
                if not used[i] and (best == -1 or pairs[i][0] > pairs[best][0]):
                    best = i
            used[best] = True
            result.append(pairs[best][1])
        return result

